mapper.select:
SELECT COALESCE(prev_post.id, 0) AS PREV , COALESCE(next_post.id, 0) AS NEXT , prev_post.subject AS PREV_SUBJECT , next_post.subject AS NEXT_SUBJECT FROM (SELECT 1) AS dummy LEFT JOIN (
SELECT id, subject FROM tb_post WHERE id < #{id}
AND public_access = true AND status = 'PUB'
ORDER BY id DESC LIMIT 1 ) prev_post ON true LEFT JOIN ( SELECT id, subject FROM tb_post WHERE id > #{id}
AND public_access = true AND status = 'PUB'
ORDER BY id ASC LIMIT 1 ) next_post ON true
